mapper.select:
SELECT u.id, u.unit_name, u.unit_code, u.building_id, bd.building_name, u.status, u.remark, u.create_time, u.update_time FROM bs_unit u LEFT JOIN bs_building bd ON u.building_id = bd.id WHERE u.del_flag = 0
AND u.unit_name LIKE CONCAT('%', #{query.unitName}, '%')
AND u.unit_code LIKE CONCAT('%', #{query.unitCode}, '%')
AND u.building_id = #{query.buildingId}
AND u.status = #{query.status}
ORDER BY u.create_time DESC
